  {
   "cell_type": "code",
   "execution_count": 51,
   "id": "702c32fe-a78d-4a48-b3d9-8c425f291035",
   "metadata": {},
   "outputs": [],
   "source": [
    "chat_history=[]\n",
    "def chat_with_bot(user_input):\n",
    "    global chat_history\n",
    "    context = retrive_context(user_input)\n",
    "    prompt  = f\"\"\" You are expert sales bot. Please refer to the context below and answer the user's question.\n",
    "              context:\n",
    "              {context}\n",
    "              user's question:\n",
    "              {user_input}\n",
    "\n",
    "              Rules:\n",
    "              - Be conventional and logical\n",
    "              - Answer only using the context\n",
    "              - If you don't know the answer, please say i don't have enough information\n",
    "              - Don't hallucinate\n",
    "              \"\"\"\n",
    "    response=gemini_model.generate_content(prompt)\n",
    "    answer=response.text\n",
    "    chat_history.append({\"User\":user_input,\"Bot\":answer})\n",
    "    return answer\n",
    "    \n",
    "    \n",
    "    \n",
    "    "
   ]
  },
